"""Localized strings for Joan HTML generated by html_generator (pl, en, de, fr, es, nl, cs)."""

from __future__ import annotations

from datetime import date

SUPPORTED_LANGS = frozenset({"pl", "en", "de", "fr", "es", "nl", "cs"})


def normalize_lang(lang: str | None) -> str:
    code = (lang or "en").lower().split("-", 1)[0]
    return code if code in SUPPORTED_LANGS else "en"


