# --- Short weekday abbreviations (grids, weather strip) ---
DAY_ABBR: dict[str, list[str]] = {
    "en": ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"],
    "pl": ["Pn", "Wt", "Śr", "Cz", "Pt", "So", "Nd"],
    "de": ["Mo", "Di", "Mi", "Do", "Fr", "Sa", "So"],
    "fr": ["lun", "mar", "mer", "jeu", "ven", "sam", "dim"],
    "es": ["lun", "mar", "mié", "jue", "vie", "sáb", "dom"],
    "nl": ["ma", "di", "wo", "do", "vr", "za", "zo"],
    "cs": ["po", "út", "st", "čt", "pá", "so", "ne"],
}

# Energy donut header: Polish uses DD.MM; others use "Mon DD Mon HH:MM"
DAY_ABBR_ENERGY_PL: list[str] = ["Pon", "Wt", "Sr", "Czw", "Pt", "Sob", "Nd"]


def format_long_date(d: date, lang: str) -> str:
    L = normalize_lang(lang)
    days = _DAY_LONG[L]
    months = _MONTH_LONG[L]
    if L == "pl":
        return f"{days[d.weekday()]}, {d.day} {months[d.month - 1]}"
    if L == "en":
        return f"{days[d.weekday()]}, {d.day} {months[d.month - 1]}"
    # fr/es/de/nl/cs: lowercase weekday + day month (common EU style)
    return f"{days[d.weekday()]}, {d.day} {months[d.month - 1]}"


def month_title(year: int, month: int, lang: str) -> str:
    L = normalize_lang(lang)
    mname = _MONTH_LONG[L][month - 1]
    if L == "pl":
        return f"{mname.capitalize()} {year}"
    if L == "en":
        return f"{mname} {year}"
    return f"{mname.capitalize()} {year}"


def day_abbr_list(lang: str) -> list[str]:
    L = normalize_lang(lang)
    return list(DAY_ABBR[L])


def day_abbr_for_energy_header(lang: str) -> list[str]:
    """Short labels for energy panel clock line."""
    if normalize_lang(lang) == "pl":
        return list(DAY_ABBR_ENERGY_PL)
    return list(DAY_ABBR[normalize_lang(lang)])


def format_energy_header_datetime(now_local, lang: str) -> str:
    """Human-readable date+time line on e-ink energy donut."""
    L = normalize_lang(lang)
    names = day_abbr_for_energy_header(L)
    t = now_local.strftime("%H:%M")
    if L == "pl":
        return f"{names[now_local.weekday()]} {now_local.day:02d}.{now_local.month:02d} {t}"
    if L == "en":
        return f"{names[now_local.weekday()]} {now_local.strftime('%d %b')} {t}"
    return f"{names[now_local.weekday()]} {now_local.day:02d}.{now_local.month:02d} {t}"


