def state_translations(lang: str) -> dict[str, str]:
    L = normalize_lang(lang)
    return dict(_STATE_MAPS.get(L) or _STATE_MAPS["en"])


def wind_direction_labels(lang: str) -> list[str]:
    """8-point compass; Polish uses Polish abbreviations."""
    if normalize_lang(lang) == "pl":
        return ["Pn", "Pn-Wsch", "Wsch", "Pd-Wsch", "Pd", "Pd-Zach", "Zach", "Pn-Zach"]
    return ["N", "NE", "E", "SE", "S", "SW", "W", "NW"]
